import React, { useState } from 'react';
import { View, Text, Image } from 'react-native';
import PaymentService from './PaymentService';

const PaymentModule = () => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [transactionData, setTransactionData] = useState(null);

  const handlePayment = async (paymentMethod) => {
    try {
      setLoading(true);
      setError(null);

      // Handle payment with selected method
      if (paymentMethod === 'creditCard') {
        const transactionData = await PaymentService.processCreditCardPayment();
        setTransactionData(transactionData);
      } else if (paymentMethod === 'digitalWallet') {
        const transactionData = await PaymentService.processDigitalWalletPayment();
        setTransactionData(transactionData);
      }

      setLoading(false);
    } catch (error) {
      setError(error.message);
      setLoading(false);
    }
  };

  return (
    <View>
      {loading && <Text>Processing payment...</Text>}
      {error && <Text>An error occurred: {error}</Text>}
      {transactionData && <Image source={{ uri: transactionData.receipt }} />}
      <Button title="Pay with Credit Card" onPress={() => handlePayment('creditCard')} />
      <Button title="Pay with Digital Wallet" onPress={() => handlePayment('digitalWallet')} />
    </View>
  );
};

export default PaymentModule;